  ('dietitian-moex-02497', 'dietitian', 'dietitian-moex-105-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '烹調肉類時，下列何種方法正確？', '["滷肉添加嫩精嫩化肉質時，應於沸騰時加入嫩精使其發揮作用，以縮短烹調時間", "pH值7～8時，肉質最硬，所以添加小蘇打提升pH值可使肉嫩化", "鹽濃度於10%時，肉的保水力最佳，如鹽焗雞的製作", "膠原蛋白及彈性蛋白較多的部位，適合加水及長時間加熱烹調"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "daeaf2290b6f", "answer_pdf_sha1": "49b5ca78f6a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02498', 'dietitian', 'dietitian-moex-105-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '製作果凍時，下列敘述何者正確？', '["吉利丁是植物膠，吉利T是動物膠", "動物膠加入酸性材料會使凝膠變硬，植物膠則相反", "植物膠與糖共煮，可增加凝固強度，動物膠溶液加糖，會降低膠體硬度", "材料先煮至沸騰後，直接加入動物膠，可使果凍快速凝膠"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "daeaf2290b6f", "answer_pdf_sha1": "49b5ca78f6a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
